import java.util.*; class Employee{ String name; int salary; Employee(String n,int s){name=n;salary=s;} public String toString(){return name+":"+salary;} } public class Five{ public static void main(String[] args){ List<Employee> list=new ArrayList<>(); list.add(new Employee("A",5000)); list.add(new Employee("B",3000)); Collections.sort(list,(a,b)->a.salary-b.salary); System.out.println(list); }}